protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: HasIndex now throws for Cosmos entities.
        // Manage indexing via Azure Portal / Bicep / Terraform instead.

        // EF Core 9: default discriminator property renamed to "$type".
        // Preserve "Discriminator" so existing documents and direct SQL
        // queries (e.g. WHERE c.Discriminator = 'Product') keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve the old "Product|123" format so FindAsync / point-reads
        // still resolve existing documents written by EF Core 8.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

